public class LunarData
{
    public DateTime Time => DateTimeOffset.FromUnixTimeSeconds(time).DateTime;
    public long time { get; set; }
    public int contributors_active { get; set; }
    public int contributors_created { get; set; }
    public long interactions { get; set; }
    public int posts_active { get; set; }
    public int posts_created { get; set; }
    public int sentiment { get; set; }
    public int spam { get; set; }
    public int alt_rank { get; set; }
    public decimal social_dominance { get; set; }
    public object  galaxy_score { get; set; }
    public int GalaxyScore { get; set; }
    public decimal open { get; set; }
    public decimal high { get; set; }
    public decimal low { get; set; }
    public decimal close { get; set; }
    public object volume_24h { get; set; }
    public double Volume24h { get; set; }
    public double market_cap { get; set; }
    public double circulating_supply { get; set; }
    public decimal market_dominance { get; set; }
    
    public static string Headers
    {
        get => "time;contributors_active;contributors_created;interactions;posts_active;posts_created;sentiment;spam;alt_rank;social_dominance;galaxy_score;open;high;low;close;volume_24h;market_cap;circulating_supply;market_dominance";
    }

    public static LunarData Parse(string line)
    {
        var parts = line.Split(';');
        return new LunarData
        {
            time = DateTimeOffset.Parse(parts[0]).ToUnixTimeSeconds(),
            contributors_active = int.Parse(parts[1]),
            contributors_created = int.Parse(parts[2]),
            interactions = long.Parse(parts[3]),
            posts_active = int.Parse(parts[4]),
            posts_created = int.Parse(parts[5]),
            sentiment = int.Parse(parts[6]),
            spam = int.Parse(parts[7]),
            alt_rank = int.Parse(parts[8]),
            social_dominance = decimal.Parse(parts[9]),
            GalaxyScore = int.Parse(parts[10]),
            open = decimal.Parse(parts[11]),
            high = decimal.Parse(parts[12]),
            low = decimal.Parse(parts[13]),
            close = decimal.Parse(parts[14]),
            Volume24h = double.Parse(parts[15]),
            market_cap = double.Parse(parts[16]),
            circulating_supply = double.Parse(parts[17]),
            market_dominance = decimal.Parse(parts[18])
        };
    }

    public override string ToString()
    {
        return $"{Time};{contributors_active};{contributors_created};{interactions};{posts_active};{posts_created};{sentiment};{spam};{alt_rank};{social_dominance};{GalaxyScore};{open};{high};{low};{close};{Volume24h};{market_cap};{circulating_supply};{market_dominance}";
    }

}   

public class LunarResponse
{
    public LunarConfig config { get; set; }
    public List<LunarData> data { get; set; }
}

public enum TimeBucket
{
    hour,
    day
}

internal class Program
{

    private const string baseurl = @"https://lunarcrush.com/api4";
    private static string token = "";
    private const string storageFolder = @"D:\Storage\Bybit\LunarCrush";

    private const string coinsPath = @"D:\Storage\Bybit\coins.csv";

    private static int coinindex = 0;

    private static Timer timer;

    private static string[] coins;

    private static async Task Main(string[] args)
    {
        var config = new ConfigurationBuilder().
            SetBasePath(Directory.GetCurrentDirectory()).
            AddJsonFile("appsettings.json", optional: false, reloadOnChange: true)
            .Build();

        token = config["MySettings:Token"];


        string symbol = "alice";
        TimeBucket bucket = TimeBucket.hour;
        DateTimeOffset start = new(2025, 1, 1, 0, 0, 0, TimeSpan.Zero);
        DateTimeOffset end = new(2026, 3, 18, 11, 0, 0, TimeSpan.Zero);

        var series = await GetCoinTimeSeriesAsync(symbol, bucket, start, end);
        //string filePath = Path.Combine(storageFolder, $"{symbol}.csv");
        //series.SaveToFile<LunarData>(filePath, LunarData.Headers);

       // await LoadCoinsInfo();

        Console.Read();

    }

    private static async Task<List<LunarData>> GetCoinTimeSeriesAsync(string symbol, TimeBucket bucket, DateTimeOffset start, DateTimeOffset end)
    {
        using (var client = new HttpClient())
        {
            var url = $"{baseurl}/public/coins/{symbol}/time-series/v2?bucket={bucket}&start={start.ToUnixTimeSeconds()}&end={end.ToUnixTimeSeconds()}";

            client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token);

            var response = await client.GetAsync(url);

            if (response.IsSuccessStatusCode)
            {
                var data = await response.Content.ReadAsStringAsync();
                var lunarResponse = System.Text.Json.JsonSerializer.Deserialize<LunarResponse>(data);

                foreach (var item in lunarResponse.data)
                {
#pragma warning disable CS8602 // Разыменование вероятной пустой ссылки.
                    var score = item.galaxy_score?.ToString().Replace("ValueKind", "").Replace("=", "").Replace("Number", "").Trim();
#pragma warning restore CS8602 // Разыменование вероятной пустой ссылки.

                    item.GalaxyScore = int.TryParse(score, out var result) ? result : -1;

#pragma warning disable CS8602 // Разыменование вероятной пустой ссылки.
                    var vol24 = item.volume_24h?.ToString().Replace("ValueKind", "").Replace("=", "").Replace("Number", "").Trim();
#pragma warning restore CS8602 // Разыменование вероятной пустой ссылки.

                    item.Volume24h = long.TryParse(vol24, out var result2) ? result2 : -1;
                }

                return lunarResponse.data;

            }
            else
            {
                Console.WriteLine($"Error: {response.StatusCode}");
            }
        }

        return null;

    }

    private static async Task LoadCoinsInfo()
    {
        Console.WriteLine("Loading coins info started.");
        coins = File.ReadAllLines(coinsPath);
        coinindex = 301;
        await LoadingLoop(315);
        //timer = new(new(OnTimerTick), null, TimeSpan.FromSeconds(1), TimeSpan.FromSeconds(7));
    }

    private static async void OnTimerTick(object state)
    {
        var coin = coins[coinindex].ToLower();
        DateTimeOffset start = new(2025, 1, 1, 0, 0, 0, TimeSpan.Zero);
        DateTimeOffset end = new(2026, 3, 18, 11, 0, 0, TimeSpan.Zero);
        var series = await GetCoinTimeSeriesAsync(coin, TimeBucket.hour, start, end);
        string filePath = Path.Combine(storageFolder, $"{coin}.csv");
        series.SaveToFile<LunarData>(filePath, LunarData.Headers);
        Console.WriteLine($"{coin} loaded, index={coinindex}.");

        if(coinindex == 9)
        {
            timer.Change(Timeout.InfiniteTimeSpan, Timeout.InfiniteTimeSpan);
            Console.WriteLine($"The loading is stopped, index={coinindex}.");
        }

        coinindex++;
    }

    private static async Task LoadingLoop(int stopindex)
    {

        while (true) 
        {
            if (coinindex >= coins.Length) { break; }

            var coin = coins[coinindex].ToLower();

            DateTimeOffset start = new(2025, 1, 1, 0, 0, 0, TimeSpan.Zero);
            DateTimeOffset end = new(2026, 3, 18, 11, 0, 0, TimeSpan.Zero);
            var series = await GetCoinTimeSeriesAsync(coin, TimeBucket.hour, start, end);
            string filePath = Path.Combine(storageFolder, $"{coin}.csv");
            series.SaveToFile<LunarData>(filePath, LunarData.Headers);
            Console.WriteLine($"{coin} loaded, index={coinindex}.");

            if (coinindex == stopindex)
                break;

            await Task.Delay(TimeSpan.FromSeconds(7));

            coinindex++;

        }

        Console.WriteLine($"The loading is stopped, index={coinindex}.");

    }






}


